        exec_timeout,
        working_dir: config.working_dir,
    };

    let node = moltis_node_host::NodeHost::new(node_config);
    node.run().await
},

NodeAction::Remove => {
    let data_dir = moltis_config::data_dir();
    moltis_node_host::service::uninstall(&data_dir)?;
    println!("Node removed.");
    Ok(())
},

